CREATE TABLE notes (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  body text NOT NULL,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE notes ENABLE ROW LEVEL SECURITY;
ALTER TABLE notes FORCE ROW LEVEL SECURITY;

CREATE POLICY notes_select_own ON notes
  FOR SELECT USING (user_id = auth.uid());

CREATE POLICY notes_insert_own ON notes
  FOR INSERT WITH CHECK (user_id = auth.uid());

CREATE MATERIALIZED VIEW mv_notes_summary AS
SELECT user_id, COUNT(*) AS note_count, MAX(created_at) AS last_note_at
FROM notes
GROUP BY user_id;

CREATE UNIQUE INDEX mv_notes_summary_pkey ON mv_notes_summary(user_id);

GRANT SELECT ON mv_notes_summary TO authenticated;
```

